final class LmdbRewritePlanTestSupport {

	private LmdbRewritePlanTestSupport() {
	}

	static String optimizedPlan(String sparql) throws IOException {
		SailRepository repository = new SailRepository(new LmdbStore(Files.createTempDirectory("lmdb-rewrite-test")
				.toFile()));
		try {
			repository.init();
			try (SailRepositoryConnection connection = repository.getConnection()) {
				return connection.prepareTupleQuery(sparql)
						.explain(Explanation.Level.Timed)
						.toString();
			}
		} finally {
			repository.shutDown();
		}
	}

	static void assertPlanContains(String plan, String expected) {
		assertThat(plan).contains(expected);
	}
}
